// TikTok Content Package Generator
// Generates: detailed content doc + image specs + caption
// Usage: node content-automation/generate-tiktok-content.mjs YYYY-MM-DD

import { writeFileSync, readFileSync } from 'fs'
import { join, dirname } from 'path'
import { fileURLToPath } from 'url'

const __dirname = dirname(fileURLToPath(import.meta.url))

// Topic database
const TOPICS = {
  'bfs-dfs': {
    title: 'BFS vs DFS — Thuật Toán Duyệt Đồ Thị',
    hook: 'Thuật toán này giúp Google tìm đường cho bạn!',
    images: [
      {
        name: 'BFS Code',
        type: 'code',
        language: 'python',
        caption: 'BFS — Breadth-First Search (Duyệt theo chiều rộng)',
        carbonTheme: 'one-dark',
        code: `from collections import deque

def bfs(graph, start):
    visited = set()
    queue = deque([start])
    visited.add(start)

    while queue:
        vertex = queue.popleft()
        print(vertex)

        for neighbor in graph[vertex]:
            if neighbor not in visited:
                visited.add(neighbor)
                queue.append(neighbor)`,
      },
      {
        name: 'DFS Code',
        type: 'code',
        language: 'python',
        caption: 'DFS — Depth-First Search (Duyệt theo chiều sâu)',
        carbonTheme: 'one-dark',
        code: `def dfs(graph, vertex, visited=None):
    if visited is None:
        visited = set()

    visited.add(vertex)
    print(vertex)

    for neighbor in graph[vertex]:
        if neighbor not in visited:
            dfs(graph, neighbor, visited)`,
      },
      {
        name: 'So sánh',
        type: 'table',
        caption: 'BFS vs DFS — Khi nào dùng cái nào?',
      },
      {
        name: 'Animation',
        type: 'concept',
        caption: 'Minh họa BFS đi từng lớp, DFS đi sâu trước',
      },
    ],
    caption: `Thuật toán này giúp Google tìm đường cho bạn 🚀

BFS vs DFS — 2 cách duyệt đồ thị phổ biến nhất:

BFS (Breadth-First Search):
✅ Tìm đường NGẮN NHẤT
✅ Duyệt theo từng lớp
✅ Dùng Queue

DFS (Depth-First Search):
✅ Tìm nhanh 1 path
✅ Topological sort
✅ Detect cycle

→ Cần đường ngắn nhất? → BFS
→ Cần topological sort? → DFS

#laptrinh #hoclaptrinh #programming #algorithm #BFS #DFS #python #ctdl`,

    hashtags: ['laptrinh', 'hoclaptrinh', 'programming', 'algorithm', 'BFS', 'DFS', 'python', 'ctdl'],
    articleSlug: 'bfs-vs-dfs-explained',
  },

  'closures': {
    title: 'JavaScript Closures',
    hook: 'Biến "private" trong JavaScript — không cần class!',
    images: [
      {
        name: 'Closure Example',
        type: 'code',
        language: 'javascript',
        caption: 'Closure — function nhớ biến bên ngoài',
        carbonTheme: 'one-dark',
        code: `function chao() {
  const tinNhan = "Xin chào!";

  return function() {
    console.log(tinNhan);
  };
}

const loiChao = chao();
loiChao(); // "Xin chào!"`,
      },
      {
        name: 'Counter',
        type: 'code',
        language: 'javascript',
        caption: 'Closure tạo private counter',
        carbonTheme: 'one-dark',
        code: `function createCounter() {
  let count = 0;  // private!

  return {
    increment: () => ++count,
    decrement: () => --count,
    getCount: () => count,
  };
}

const counter = createCounter();
counter.increment();
counter.increment();
counter.getCount(); // 2`,
      },
      {
        name: 'Common Mistake',
        type: 'code',
        language: 'javascript',
        caption: 'Lỗi thường gặp: var trong vòng for',
        carbonTheme: 'dracula',
        code: `// ❌ SAI — var không block-scoped
for (var i = 0; i < 3; i++) {
  setTimeout(() => console.log(i), 100);
}
// Output: 3, 3, 3

// ✅ ĐÚNG — dùng let
for (let i = 0; i < 3; i++) {
  setTimeout(() => console.log(i), 100);
}
// Output: 0, 1, 2`,
      },
    ],
    caption: `Biến "private" trong JavaScript — không cần class! 🔒

Closure = function nhớ biến bên ngoài dù đã return

Ví dụ:
- Tạo counter không cần class
- Module pattern ( Encapsulation)
- Factory function

Lỗi phổ biến: dùng var trong vòng for với setTimeout → dùng let thay thế

#javascript #closures #webdev #programming #hoclaptrinh`,

    hashtags: ['javascript', 'closures', 'webdev', 'programming', 'hoclaptrinh'],
    articleSlug: 'javascript-closures-explained',
  },

  'dp': {
    title: 'Dynamic Programming — 3 Bài Toán FAANG Hay Hỏi',
    hook: '3 bài toán Dynamic Programming mà FAANG hay hỏi. Bạn có giải được không?',
    images: [
      {
        name: 'Fibonacci DP',
        type: 'code',
        language: 'python',
        caption: 'Fibonacci với DP — Memoization vs Tabulation',
        carbonTheme: 'one-dark',
        code: `# ❌ Naive recursion — O(2^n)
def fib_naive(n):
    if n <= 1: return n
    return fib_naive(n-1) + fib_naive(n-2)

# ✅ Top-down DP (Memoization) — O(n)
def fib_memo(n, memo={}):
    if n in memo: return memo[n]
    if n <= 1: return n
    memo[n] = fib_memo(n-1, memo) + fib_memo(n-2, memo)
    return memo[n]

# ✅ Bottom-up DP (Tabulation) — O(n)
def fib_tab(n):
    if n <= 1: return n
    dp = [0] * (n + 1)
    dp[1] = 1
    for i in range(2, n + 1):
        dp[i] = dp[i-1] + dp[i-2]
    return dp[n]`,
      },
      {
        name: 'Knapsack DP',
        type: 'code',
        language: 'python',
        caption: '0/1 Knapsack — Bài toán túi mang về cân nặng tối đa',
        carbonTheme: 'dracula',
        code: `def knapsack(weights, values, capacity):
    n = len(weights)
    dp = [[0] * (capacity + 1) for _ in range(n + 1)]

    for i in range(1, n + 1):
        for w in range(capacity + 1):
            if weights[i-1] <= w:
                dp[i][w] = max(
                    values[i-1] + dp[i-1][w - weights[i-1]],
                    dp[i-1][w]
                )
            else:
                dp[i][w] = dp[i-1][w]

    return dp[n][capacity]

# Ví dụ: túi 5kg, đồ [2kg/3$, 3kg/4$, 4kg/5$]
print(knapsack([2,3,4], [3,4,5], 5))  # Output: 7`,
      },
      {
        name: 'LCS DP',
        type: 'code',
        language: 'python',
        caption: 'Longest Common Subsequence — Tìm chuỗi con chung dài nhất',
        carbonTheme: 'one-dark',
        code: `def lcs(s1, s2):
    m, n = len(s1), len(s2)
    dp = [[0] * (n + 1) for _ in range(m + 1)]

    for i in range(1, m + 1):
        for j in range(1, n + 1):
            if s1[i-1] == s2[j-1]:
                dp[i][j] = dp[i-1][j-1] + 1
            else:
                dp[i][j] = max(dp[i-1][j], dp[i][j-1])

    return dp[m][n]

print(lcs("AGGTAB", "GXTXAYB"))  # Output: 4 (GTAB)`,
      },
      {
        name: 'DP Cheat Sheet',
        type: 'table',
        caption: 'Khi nào dùng DP? — Checklist nhanh',
      },
    ],
    caption: `3 bài toán Dynamic Programming mà FAANG hay hỏi 👇

Fibonacci → Knapsack → LCS

Đây là 3 bài kinh điển mà 90% developer giải SAI vì không hiểu DP

Công thức:
1. Tìm trạng thái nhỏ nhất (base case)
2. Định nghĩa state dp[i] / dp[i][j]
3. Tìm công thức chuyển trạng thái (transition)
4. Tính từ nhỏ đến lớn

Mẹo: Vẽ bảng dp trước khi code → thấy ngay pattern

#dynamicprogramming #algorithm #faang #interview #python #laptrinh #ctdl`,
    hashtags: ['dynamicprogramming', 'algorithm', 'faang', 'interview', 'python', 'laptrinh', 'ctdl'],
    articleSlug: 'dynamic-programming-explained',
  },

  'binary-search': {
    title: 'Binary Search — Tìm kiếm nhanh gấp 100 lần',
    hook: 'Thuật toán tìm kiếm nhanh gấp 100 lần — bạn đang dùng sai?',
    images: [
      {
        name: 'Binary Search Code',
        type: 'code',
        language: 'python',
        caption: 'Binary Search — O(log n)',
        carbonTheme: 'one-dark',
        code: `def binary_search(arr, target):
    left, right = 0, len(arr) - 1

    while left <= right:
        mid = (left + right) // 2

        if arr[mid] == target:
            return mid
        elif arr[mid] < target:
            left = mid + 1
        else:
            right = mid - 1

    return -1

# Ví dụ: mảng 1 triệu phần tử
# Linear search: 500,000 bước (trung bình)
# Binary search: 20 bước! ⚡`,
      },
    ],
    caption: `Thuật toán tìm kiếm nhanh gấp 100 lần ⚡

Mảng 1 triệu phần tử:
- Linear search: 500,000 bước
- Binary search: 20 bước!

Điều kiện: Mảng phải SORTED

Cách hoạt động: chia đôi liên tục → tìm nhanh

#algorithm #binarysearch #python #laptrinh #ctdl`,
    hashtags: ['algorithm', 'binarysearch', 'python', 'laptrinh', 'ctdl'],
    articleSlug: 'binary-search',
  },
}

// Default fallback for unknown topics
const DEFAULT_TOPIC = {
  title: 'Algorithm',
  hook: 'Thuật toán mọi developer phải biết!',
  images: [],
  caption: '',
  hashtags: ['laptrinh', 'hoclaptrinh', 'programming'],
  articleSlug: '',
}

function generateCarbonUrl(code, theme = 'one-dark', language = 'python') {
  const encoded = encodeURIComponent(code)
  return `https://carbon.now.sh/?bg=rgba(10%2C10%2C26%2C1)&t=${theme}&l=${language}&code=${encoded}`
}

function generateTopicContent(date, topicSlug) {
  const topic = TOPICS[topicSlug] || { ...DEFAULT_TOPIC, title: topicSlug }

  const images = topic.images.map((img, i) => {
    if (img.type === 'code') {
      return {
        ...img,
        carbonUrl: generateCarbonUrl(img.code, img.carbonTheme, img.language),
        note: 'Copy URL → mở trình duyệt → Save Image',
      }
    }
    return {
      ...img,
      note: 'Tạo bằng Canva/Figma với style: bg #0a0a1a, text trắng',
    }
  })

  return {
    date,
    topic: topic.title,
    hook: topic.hook,
    articleUrl: `/articles/${topic.articleSlug}`,
    images,
    caption: topic.caption,
    hashtags: topic.hashtags,
    postingTime: '17:00 ICT',
  }
}

// CLI
const date = process.argv[2] || new Date().toISOString().split('T')[0]
const topicSlug = process.argv[3] || 'bfs-dfs'

const content = generateTopicContent(date, topicSlug)
const outputDir = join(__dirname, 'tiktok-content')
const outputFile = join(outputDir, `${date}.md`)

// Write content package
let md = `# TikTok Content Package — ${content.topic}\n`
md += `# Ngày: ${date}\n\n`
md += `---\n\n`
md += `## HOOK\n> ${content.hook}\n\n`
md += `## LINK BÀI VIẾT\n${content.articleUrl}\n\n`
md += `---\n\n`

md += `## HÌNH ẢNH (${content.images.length} ảnh)\n\n`
content.images.forEach((img, i) => {
  md += `### Ảnh ${i + 1}: ${img.name}\n`
  md += `**Type:** ${img.type}\n`
  md += `**Caption:** ${img.caption}\n`
  if (img.carbonUrl) {
    md += `**Carbon URL:** ${img.carbonUrl}\n`
  }
  md += `**Cách tạo:** ${img.note}\n\n`
})

md += `---\n\n`
md += `## CAPTION TIKTOK\n\n`
md += `\`\`\`\n${content.caption}\n\`\`\`\n\n`
md += `---\n\n`
md += `## HASHTAGS\n\n`
md += content.hashtags.map(t => `#${t}`).join(' ') + '\n\n'
md += `---\n\n`
md += `## GIỜ ĐĂNG\n\n`
md += `${content.postingTime}\n`

// Ensure directory exists
import('fs').then(({ existsSync, mkdirSync }) => {
  if (!existsSync(outputDir)) mkdirSync(outputDir, { recursive: true })
  writeFileSync(outputFile, md)
  console.log(`✅ Generated: ${outputFile}`)
  console.log(`Topic: ${content.topic}`)
  console.log(`Images: ${content.images.length}`)
  console.log(`Article: ${content.articleUrl}`)
  content.images.forEach((img, i) => {
    if (img.carbonUrl) {
      console.log(`  ${i + 1}. ${img.carbonUrl}`)
    } else {
      console.log(`  ${i + 1}. ${img.name} — ${img.note}`)
    }
  })
})

