function generateCarbonUrl(code, theme = 'one-dark', language = 'python') {
  const encoded = encodeURIComponent(code)
  return `https://carbon.now.sh/?bg=rgba(10%2C10%2C26%2C1)&t=${theme}&l=${language}&code=${encoded}`
}

function generateProblemUrl(text, theme = 'one-dark') {
  // Convert plain text to python comment style for Carbon.now.sh
  const code = text.split('\n').map(line => `# ${line}`).join('\n')
  return generateCarbonUrl(code, theme, 'python')
}

function generateTopicContent(date, topicSlug) {
  const topic = TOPICS[topicSlug] || { ...DEFAULT_TOPIC, title: topicSlug }

  const images = topic.images.map((img, i) => {
    if (img.type === 'code') {
      return {
        ...img,
        carbonUrl: generateCarbonUrl(img.code, img.carbonTheme, img.language),
        note: 'Copy URL → mở trình duyệt → Save Image',
      }
    } else if (img.type === 'problem') {
      return {
        ...img,
        carbonUrl: generateProblemUrl(img.problemText, 'one-dark'),
        note: 'Copy URL → mở trình duyệt → Save Image (text hiển thị dạng comment)',
      }
    } else if (img.type === 'thumbnail') {
      return {
        ...img,
        note: img.note,
      }
    }
    return {
      ...img,
      note: 'Tạo bằng Canva/Figma với style: bg #0a0a1a, text trắng',
    }
  })

  return {
    date,
    topic: topic.title,
    hook: topic.hook,
    articleUrl: `/articles/${topic.articleSlug}`,
    images,
    caption: topic.caption,
    hashtags: topic.hashtags,
    postingTime: '17:00 ICT',
  }
}

